using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter;

    public StringFormatterTests()
    {
        _formatter = new StringFormatter();
    }

    #region FormatPhoneNumber

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.StartsWith("(555)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.EndsWith("4567", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesExpectedFormat()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.MatchesRegex(@"\(\d{3}\) \d{3}-\d{4}", result);
    }

    [TestMethod]
    [DataRow("5551234567", "(555) 123-4567")]
    [DataRow("8005551212", "(800) 555-1212")]
    [DataRow("0000000000", "(000) 000-0000")]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber(string digits, string expected)
    {
        var result = _formatter.FormatPhoneNumber(digits);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Null_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.FormatPhoneNumber(null!));

        Assert.AreEqual("digits", ex.ParamName);
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    public void FormatPhoneNumber_InvalidLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.FormatPhoneNumber(digits));
    }

    #endregion

    #region BuildGreeting

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith("Dear Mr.", result);
    }

    [TestMethod]
    public void BuildGreeting_WithName_EndsWithNameAndComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.EndsWith("Smith,", result);
    }

    [TestMethod]
    [DataRow("Smith", "Dr.", "Dear Dr. Smith,")]
    [DataRow("Jones", "Ms.", "Dear Ms. Jones,")]
    [DataRow("Lee", "Mr.", "Dear Mr. Lee,")]
    public void BuildGreeting_WithTitleAndName_ReturnsFormattedGreeting(
        string name, string title, string expected)
    {
        var result = _formatter.BuildGreeting(name, title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void BuildGreeting_ContainsName()
    {
        var result = _formatter.BuildGreeting("Johnson", "Prof.");

        Assert.Contains("Johnson", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_NullOrWhitespaceName_Throws(string? name)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.BuildGreeting(name!));
    }

    #endregion

    #region GenerateSlug

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ReplacesWithHyphens()
    {
        var result = _formatter.GenerateSlug("C# is Awesome!!!");

        Assert.MatchesRegex(@"^[a-z0-9]+(-[a-z0-9]+)*$", result);
    }

    [TestMethod]
    public void GenerateSlug_Result_DoesNotStartWithHyphen()
    {
        var result = _formatter.GenerateSlug("  --Leading Dashes");

        Assert.StartsWith("l", result);
    }

    [TestMethod]
    public void GenerateSlug_Result_DoesNotEndWithHyphen()
    {
        var result = _formatter.GenerateSlug("Trailing Dashes--  ");

        Assert.EndsWith("s", result);
    }

    [TestMethod]
    [DataRow("Hello World", "hello-world")]
    [DataRow("My Blog Post!", "my-blog-post")]
    [DataRow("  Spaces  Everywhere  ", "spaces-everywhere")]
    [DataRow("ALL CAPS TITLE", "all-caps-title")]
    public void GenerateSlug_VariousTitles_ReturnsExpectedSlug(string title, string expected)
    {
        var result = _formatter.GenerateSlug(title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_NullOrWhitespace_Throws(string? title)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.GenerateSlug(title!));
    }

    #endregion

    #region FormatCurrency

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_EuroSymbol_StartsWithEuro()
    {
        var result = _formatter.FormatCurrency(42.50m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_TwoDecimalPlaces_EndsWithDecimals()
    {
        var result = _formatter.FormatCurrency(10m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    [DataRow(10.5, "$10.50")]
    [DataRow(0.0, "$0.00")]
    [DataRow(1234.56, "$1234.56")]
    public void FormatCurrency_VariousAmounts_ReturnsFormattedString(double amount, string expected)
    {
        var result = _formatter.FormatCurrency((decimal)amount);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        var result = _formatter.FormatCurrency(-5.99m);

        Assert.Contains("-", result);
    }

    #endregion
}

